INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (470, 159881, 7, 725, '厦门 C.F. .....', '终于又回来了，久违的故土。虽然到厦门时，已是中午，可是烈日下的她没有给我丝毫得热意。微微的海风，让人感到好舒心，好清爽。我想常住在厦门的人是不会感觉到得――因为从前我也和你一样不这么认为。现在去福州，被那儿真正叫烈日的东西晒得我不行了，我是“wo da san”地回来得。：（那真的可以说是福建的火炉，那的热是闷出来的，没有一丝的风，很小气！：（那树叶象死了似的，一动都不动，就象人的心――死了似的。
<br>回来了，在耳根萦绕的亲切可人的闽南语，爽；在福州，成天就是叽里呱啦的福州话，烦！：（
<br>一到家，东西扔了，人就跑去逛了。记得，寒假，三年没从新西兰回来的老同学说厦门一点也没有变。说实话，我倒不觉得，每次回来，我都觉得厦门有变化，是多是少而已。做个生活的有心人，你会发现厦门一直在变！从前，我也不是很喜欢，因为我每天都在她的怀抱里，现在，一年最多也只有三个月，真的觉得这是一个很适合生活的城市，但是，并不适合挣钱。呵呵，不知大家是否赞同。', '终于又回来了，久违的故土。虽然到厦门时，已是中午，可是烈日下的她没有给我丝毫得热意。微微的海风，让人感到好舒心，好清爽。我想常住在厦门的人是不会感觉到得――因为从前我也和你一样不这么认为。现在去福州，被那儿真正叫烈日的东西晒得我不行了，我是“wo da san”地回来得。：（那真的可以说是福建的火炉，那的热是闷出来的，没有一丝的风，很小气！：（那树叶象死了似的，一动都不动，就象人的心――死了似的。

回来了，在耳根萦绕的亲切可人的闽南语，爽；在福州，成天就是叽里呱啦的福州话，烦！：（

一到家，东西扔了，人就跑去逛了。记得，寒假，三年没从新西兰回来的老同学说厦门一点也没有变。说实话，我倒不觉得，每次回来，我都觉得厦门有变化，是多是少而已。做个生活的有心人，你会发现厦门一直在变！从前，我也不是很喜欢，因为我每天都在她的怀抱里，现在，一年最多也只有三个月，真的觉得这是一个很适合生活的城市，但是，并不适合挣钱。呵呵，不知大家是否赞同。', NULL, '2002-05-01 15:23:00', 1, '20020616003628_bbsid_159881_board_7_e4ea9fef51.html', '20020616003628');
